public class JavaBeanSerializer
        implements ObjectSerializer {
    private final ObjectWriter raw;

    public JavaBeanSerializer(ObjectWriter raw) {
        this.raw = raw;
    }

    @Override
    public void write(
            JSONSerializer serializer,
            Object object,
            Object fieldName,
            Type fieldType,
            int features
    ) throws IOException {
        JSONWriter jsonWriter = serializer.out.raw;
        raw.write(jsonWriter, object, fieldName, fieldType, 0L);
    }

    public Object getFieldValue(Object object, String key) {
        FieldWriter fieldWriter = raw.getFieldWriter(key);
        if (fieldWriter == null) {
            return null;
        }
        return fieldWriter.getFieldValue(object);
    }
}

public class SimpleDateFormatSerializer
        implements ObjectSerializer {
    private final String pattern;

    public SimpleDateFormatSerializer(String pattern) {
        this.pattern = pattern;
    }

    public void write(JSONSerializer serializer,
                      Object object,
                      Object fieldName,
                      Type fieldType,
                      int features) throws IOException {
        if (object == null) {
            serializer.out.writeNull();
            return;
        }

        Date date = (Date) object;
        SimpleDateFormat format = new SimpleDateFormat(pattern);
        String text = format.format(date);
        serializer.write(text);
    }
}

@Service
public class NamespaceConfigInfoService extends AbstractNamespaceDetailInjector {

    private final ConfigInfoPersistService configInfoPersistService;

    public NamespaceConfigInfoService(ConfigInfoPersistService configInfoPersistService) {
        this.configInfoPersistService = configInfoPersistService;
    }

    @Override
    public void injectDetail(Namespace namespace) {

        if (EnvUtil.getProperty(PropertiesConstant.DEFAULT_TENANT_QUOTA, Integer.class) != null) {
            namespace.setQuota(
                EnvUtil.getProperty(PropertiesConstant.DEFAULT_TENANT_QUOTA, Integer.class));
        }

        // set config count.
        int configCount = configInfoPersistService.configInfoCount(namespace.getNamespace());
        namespace.setConfigCount(configCount);
    }
}

@Configuration
@NacosWebBean
public class HttpRequestContextConfig {

    @Bean
    public FilterRegistrationBean<HttpRequestContextFilter> requestContextFilterRegistration(
        HttpRequestContextFilter requestContextFilter) {
        FilterRegistrationBean<HttpRequestContextFilter> registration =
            new FilterRegistrationBean<>();
        registration.setFilter(requestContextFilter);
        registration.addUrlPatterns("/*");
        registration.setName("nacosRequestContextFilter");
        registration.setOrder(Integer.MIN_VALUE);
        return registration;
    }

    @Bean
    public HttpRequestContextFilter nacosRequestContextFilter() {
        return new HttpRequestContextFilter();
    }
}

public class ConnectionBasedClientFactory implements ClientFactory<ConnectionBasedClient> {

    @Override
    public String getType() {
        return ClientConstants.DEFAULT_FACTORY;
    }

    @Override
    public ConnectionBasedClient newClient(String clientId, ClientAttributes attributes) {
        long revision = attributes.getClientAttribute(REVISION, 0);
        ConnectionBasedClient connectionBasedClient =
            new ConnectionBasedClient(clientId, true, revision);
        connectionBasedClient.setAttributes(attributes);
        return connectionBasedClient;
    }

    @Override
    public ConnectionBasedClient newSyncedClient(String clientId, ClientAttributes attributes) {
        long revision = attributes.getClientAttribute(REVISION, 0);
        ConnectionBasedClient connectionBasedClient =
            new ConnectionBasedClient(clientId, false, revision);
        connectionBasedClient.setAttributes(attributes);
        return connectionBasedClient;
    }
}

