public class TimeWindowCompactionController extends CompactionController
{
    private static final Logger logger = LoggerFactory.getLogger(TimeWindowCompactionController.class);

    private final boolean ignoreOverlaps;

    public TimeWindowCompactionController(ColumnFamilyStore cfs, Set<SSTableReader> compacting, long gcBefore, boolean ignoreOverlaps)
    {
        super(cfs, compacting, gcBefore);
        this.ignoreOverlaps = ignoreOverlaps;
        if (ignoreOverlaps)
            logger.warn("You are running with sstables overlapping checks disabled, it can result in loss of data");
    }

    @Override
    protected boolean ignoreOverlaps()
    {
        return ignoreOverlaps;
    }
}

public class ClientHAProxyFactory<T> implements HAProxyFactory<T> {

  private AlignmentContext alignmentContext;

  public void setAlignmentContext(AlignmentContext alignmentContext) {
    this.alignmentContext = alignmentContext;
  }

  @Override
  @SuppressWarnings("unchecked")
  public T createProxy(Configuration conf, InetSocketAddress nnAddr,
      Class<T> xface, UserGroupInformation ugi, boolean withRetries,
      AtomicBoolean fallbackToSimpleAuth) throws IOException {
    if (alignmentContext != null) {
      return (T) NameNodeProxiesClient.createProxyWithAlignmentContext(
        nnAddr, conf, ugi, false, fallbackToSimpleAuth, alignmentContext);
    }
    return (T) NameNodeProxiesClient.createNonHAProxyWithClientProtocol(
      nnAddr, conf, ugi, false, fallbackToSimpleAuth);
  }

  @Override
  public T createProxy(Configuration conf, InetSocketAddress nnAddr,
      Class<T> xface, UserGroupInformation ugi, boolean withRetries)
      throws IOException {
    return createProxy(conf, nnAddr, xface, ugi, withRetries, null);
  }
}

public enum FederationNamenodeServiceState {
  ACTIVE, // HAServiceState.ACTIVE or operational.
  OBSERVER, // HAServiceState.OBSERVER.
  STANDBY, // HAServiceState.STANDBY.
  UNAVAILABLE, // When the namenode cannot be reached.
  EXPIRED, // When the last update is too old.
  DISABLED; // When the nameservice is disabled.

  public static FederationNamenodeServiceState getState(HAServiceState state) {
    switch(state) {
    case ACTIVE:
      return FederationNamenodeServiceState.ACTIVE;
    case OBSERVER:
      return FederationNamenodeServiceState.OBSERVER;
    case STANDBY:
      return FederationNamenodeServiceState.STANDBY;
    case INITIALIZING:
      return FederationNamenodeServiceState.UNAVAILABLE;
    case STOPPING:
      return FederationNamenodeServiceState.UNAVAILABLE;
    default:
      return FederationNamenodeServiceState.UNAVAILABLE;
    }
  }
}

public class LeaderFollowerResolver implements OrderedResolver {
  protected static final Logger LOG =
      LoggerFactory.getLogger(LeaderFollowerResolver.class);

  @Override
  public String getFirstNamespace(String path, PathLocation loc) {
    try {
      // Always return first destination.
      // In leader/follower mode, admin add sub-clusters
      // by the order of leader,follower,follower...
      // The first element is always the leader sub-cluster,
      // so invoking getDefaultLocation is suitable here.
      RemoteLocation remoteLocation = loc.getDefaultLocation();
      return remoteLocation.getNameserviceId();
    } catch (Exception ex) {
      LOG.error("Cannot find sub-cluster for {}", loc);
      return null;
    }
  }
}

